import React, { useEffect, useState } from "react";
import API from "../api/api";

function AdminDashboard() {
  const [kpis, setKpis] = useState({});

  useEffect(() => {
    API.get("/admin/kpis?date=2025-09-02")
      .then((res) => setKpis(res.data))
      .catch((err) => console.log(err));
  }, []);

  return (
    <div>
      <h2 className="text-xl font-bold mb-2">Admin KPIs</h2>
      <ul>
        <li>Avg Wait Time: {kpis.avg_wait_time} min</li>
        <li>Buses Used: {kpis.buses_used}</li>
        <li>Load Factor: {kpis.load_factor}</li>
      </ul>
    </div>
  );
}

export default AdminDashboard;
